class Solution {
    // Function to calculate the shortest transformation sequence length
    wordLadderLength(startWord, targetWord, wordList) {
        let q = [[startWord, 1]];
        let st = new Set(wordList);
        st.delete(startWord);

        while (q.length > 0) {
            let [word, steps] = q.shift();

            // If target word is found
            if (word === targetWord) return steps;

            // Try changing every character
            for (let i = 0; i < word.length; i++) {
                for (let ch = 97; ch <= 122; ch++) {
                    let newWord = word.substring(0, i) + String.fromCharCode(ch) + word.substring(i + 1);
                    if (st.has(newWord)) {
                        st.delete(newWord);
                        q.push([newWord, steps + 1]);
                    }
                }
            }
        }
        return 0;
    }
}

